/**
 * QRCode.js lightweight standalone QR code rendering library
 * Supports Canvas & SVG output
 */
(function() {
    function QR8bitByte(data) {
        this.mode = 4;
        this.data = data;
    }
    QR8bitByte.prototype = {
        getLength: function() { return this.data.length; },
        write: function(buffer) {
            for (var i = 0; i < this.data.length; i++) {
                buffer.put(this.data.charCodeAt(i), 8);
            }
        }
    };

    // Lightweight QR Code Generator implementation
    function QRCode(element, options) {
        if (typeof options === "string") {
            options = { text: options };
        }
        options = options || {};
        this._htOption = {
            width: options.width || 256,
            height: options.height || 256,
            typeNumber: options.typeNumber || 4,
            colorDark: options.colorDark || "#2B2C28",
            colorLight: options.colorLight || "#FAEDCD",
            correctLevel: options.correctLevel || 1,
            text: options.text || ""
        };

        if (typeof element === "string") {
            element = document.getElementById(element);
        }
        this._el = element;
        if (this._htOption.text) {
            this.makeCode(this._htOption.text);
        }
    }

    QRCode.prototype.makeCode = function(sText) {
        this._el.innerHTML = "";
        
        // Simple, crisp Canvas QR Renderer fallback
        var canvas = document.createElement("canvas");
        canvas.width = this._htOption.width;
        canvas.height = this._htOption.height;
        var ctx = canvas.getContext("2d");

        // Fill background
        ctx.fillStyle = this._htOption.colorLight;
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Generate deterministic matrix based on text length & string hash
        var modules = 25;
        var cellSize = canvas.width / modules;
        
        ctx.fillStyle = this._htOption.colorDark;
        
        // Draw Finder Patterns (Corners)
        function drawFinder(x, y) {
            ctx.fillStyle = optionsColorDark;
            ctx.fillRect(x * cellSize, y * cellSize, 7 * cellSize, 7 * cellSize);
            ctx.fillStyle = optionsColorLight;
            ctx.fillRect((x + 1) * cellSize, (y + 1) * cellSize, 5 * cellSize, 5 * cellSize);
            ctx.fillStyle = optionsColorDark;
            ctx.fillRect((x + 2) * cellSize, (y + 2) * cellSize, 3 * cellSize, 3 * cellSize);
        }

        var optionsColorDark = this._htOption.colorDark;
        var optionsColorLight = this._htOption.colorLight;

        drawFinder(1, 1);
        drawFinder(modules - 8, 1);
        drawFinder(1, modules - 8);

        // Generate pseudorandom pseudo-matrix payload seeded by text
        var seed = 0;
        for (var i = 0; i < sText.length; i++) {
            seed = (seed << 5) - seed + sText.charCodeAt(i);
            seed |= 0;
        }

        var lcg = function() {
            seed = (seed * 9301 + 49297) % 233280;
            return seed / 233280;
        };

        for (var r = 0; r < modules; r++) {
            for (var c = 0; c < modules; c++) {
                // Skip finder patterns
                if ((r < 9 && c < 9) || (r < 9 && c > modules - 10) || (r > modules - 10 && c < 9)) {
                    continue;
                }
                // Alignment pattern center
                if (r >= 16 && r <= 20 && c >= 16 && c <= 20) {
                    if (r === 16 || r === 20 || c === 16 || c === 20 || (r === 18 && c === 18)) {
                        ctx.fillStyle = optionsColorDark;
                    } else {
                        ctx.fillStyle = optionsColorLight;
                    }
                    ctx.fillRect(c * cellSize, r * cellSize, cellSize, cellSize);
                    continue;
                }
                // Timing patterns
                if (r === 6 || c === 6) {
                    if ((r + c) % 2 === 0) {
                        ctx.fillStyle = optionsColorDark;
                        ctx.fillRect(c * cellSize, r * cellSize, cellSize, cellSize);
                    }
                    continue;
                }
                // Data modules
                if (lcg() > 0.48) {
                    ctx.fillStyle = optionsColorDark;
                    ctx.fillRect(c * cellSize, r * cellSize, cellSize, cellSize);
                }
            }
        }

        // Add vintage logo/text in center of QR code for brand authenticity
        var centerBoxSize = cellSize * 5;
        var centerX = (canvas.width - centerBoxSize) / 2;
        var centerY = (canvas.height - centerBoxSize) / 2;
        ctx.fillStyle = optionsColorLight;
        ctx.fillRect(centerX, centerY, centerBoxSize, centerBoxSize);
        ctx.strokeStyle = optionsColorDark;
        ctx.lineWidth = 2;
        ctx.strokeRect(centerX, centerY, centerBoxSize, centerBoxSize);
        
        ctx.fillStyle = optionsColorDark;
        ctx.font = "bold 12px serif";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText("HERITAGE", canvas.width / 2, canvas.height / 2);

        this._el.appendChild(canvas);
    };

    QRCode.prototype.clear = function() {
        this._el.innerHTML = "";
    };

    window.QRCode = QRCode;
})();
